                    if target_mem_i > GPU_MEM_SIZE or target_mem_j > GPU_MEM_SIZE:
                        continue

                    individual[i], individual[j] = gpu_j, gpu_i
                    new_placement = decode_individual(individual)
                    new_fitness = calculate_fitness(new_placement)

                    if new_fitness < current_fitness - 1e-9:
                        current_fitness = new_fitness
                        current_placement = new_placement
                        improved = True
                        break
                    else:
                        individual[i], individual[j] = gpu_i, gpu_j

            if not improved:
                break

        return individual

    POPULATION_SIZE = max(30, 3 * gpu_num)
