    def kvpr_for_gpu(gpu_models):
        if not gpu_models:
            return 0.0
        total_model_size = sum(m.model_size for m in gpu_models)
        if total_model_size >= GPU_MEM_SIZE:
            return float('inf')
        total_pressure = sum(m.req_rate / m.slo for m in gpu_models)
        remaining = GPU_MEM_SIZE - total_model_size
        return total_pressure / remaining

    def max_kvpr(placement):
        max_val = 0.0
        for gpu_id in range(gpu_num):
            kvpr = kvpr_for_gpu(placement[gpu_id])
            if kvpr == float('inf'):
                return float('inf')
            max_val = max(max_val, kvpr)
        return max_val

    # Initial greedy placement using best-fit decreasing by model_size
    sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)
    placement = {i: [] for i in range(gpu_num)}
    gpu_sizes = [0] * gpu_num

    for model in sorted_models:
        best_gpu = -1
        best_kvpr_increase = float('inf')

        for gpu_id in range(gpu_num):
            if gpu_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                temp_kvpr = kvpr_for_gpu(placement[gpu_id] + [model])
                if temp_kvpr < best_kvpr_increase:
                    best_kvpr_increase = temp_kvpr
                    best_gpu = gpu_id

        if best_gpu != -1:
            placement[best_gpu].append(model)
            gpu_sizes[best_gpu] += model.model_size
        else:
            # Should not happen with problem constraints
            placement[0].append(model)
            gpu_sizes[0] += model.model_size

    best_placement = {k: list(v) for k, v in placement.items()}
    best_score = max_kvpr(best_placement)

    # Simulated annealing with moves and swaps
    def perturb(current_pl, current_sizes):
        new_pl = {k: list(v) for k, v in current_pl.items()}
        new_sizes = list(current_sizes)

        # Randomly choose move type: 0=move, 1=swap
        move_type = random.randint(0, 1)

        if move_type == 0:  # Move a model
            src_gpu = random.randint(0, gpu_num-1)
            if not new_pl[src_gpu]:
                return current_pl, current_sizes
