        return max(kvprs) if kvprs else 0.0

    # Greedy initialization
    placement = greedy_placement()

    # Local search: try swapping models between GPUs
    def local_search(current_placement):
        best_placement = [gpu_models[:] for gpu_models in current_placement]
        best_fitness = calculate_fitness(best_placement)

        improved = True
