                            new_placement[gpu1].append(model2)
                            new_placement[gpu2].append(model1)

                            # Check memory constraints
                            gpu1_mem = sum(m.model_size for m in new_placement[gpu1])
                            gpu2_mem = sum(m.model_size for m in new_placement[gpu2])

                            if gpu1_mem <= GPU_MEM_SIZE and gpu2_mem <= GPU_MEM_SIZE:
                                new_fitness = calculate_fitness(new_placement)
                                if new_fitness < best_fitness:
                                    best_fitness = new_fitness
                                    best_placement = new_placement
                                    improved = True
                                    current_placement = new_placement
                                    break
                        if improved:
