    '''
    GPU_MEM_SIZE = 80
    MAX_ITERATIONS = 1000  # Increased iterations for potentially better convergence
    MAX_RETRIES = 5       # Number of attempts with different initializations

    def calculate_gpu_kvpr(gpu_models, gpu_current_size):
        if gpu_current_size >= GPU_MEM_SIZE:
            return float('inf')
        if not gpu_models:
            return 0.0
        total_req_rate_slo = sum(m.req_rate / m.slo for m in gpu_models)
        remaining_mem = GPU_MEM_SIZE - gpu_current_size
        return total_req_rate_slo / remaining_mem

    def calculate_max_kvpr(placement):
        max_kvpr = 0.0
        for gpu_id in range(gpu_num):
            gpu_models = placement.get(gpu_id, [])
            gpu_current_size = sum(m.model_size for m in gpu_models)
            kvpr = calculate_gpu_kvpr(gpu_models, gpu_current_size)
            if kvpr == float('inf'):
                return float('inf')
            max_kvpr = max(max_kvpr, kvpr)
        return max_kvpr

    def greedy_initial_placement():
        # Sort models by some heuristic. Here, prioritizing models that are "heavy" on req_rate/slo
        # relative to their size. Or, could sort by req_rate/slo directly.
        # Let's try sorting by req_rate/slo in descending order.
        sorted_models = sorted(models, key=lambda m: m.req_rate / m.slo, reverse=True)

        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        gpu_current_sizes = {gpu_id: 0 for gpu_id in range(gpu_num)}
        gpu_kvprs = {gpu_id: 0.0 for gpu_id in range(gpu_num)}

        for model in sorted_models:
            best_gpu = -1
            min_increase_in_max_kvpr = float('inf')

            # Find the GPU that results in the minimum increase in the overall max KVPR
            # or simply the best KVPR for itself if all GPUs are underutilized.
            for gpu_id in range(gpu_num):
                if gpu_current_sizes[gpu_id] + model.model_size <= GPU_MEM_SIZE:
                    # Temporarily add model to calculate potential new max KVPR
                    temp_gpu_models = placement[gpu_id] + [model]
                    temp_gpu_size = gpu_current_sizes[gpu_id] + model.model_size
                    temp_gpu_kvpr = calculate_gpu_kvpr(temp_gpu_models, temp_gpu_size)

                    # Calculate the max KVPR if this model is placed on gpu_id
                    current_max_kvpr = calculate_max_kvpr(placement)
                    potential_max_kvpr = max(current_max_kvpr, temp_gpu_kvpr)

                    if potential_max_kvpr < min_increase_in_max_kvpr:
                        min_increase_in_max_kvpr = potential_max_kvpr
                        best_gpu = gpu_id
                    elif potential_max_kvpr == min_increase_in_max_kvpr:
                        # Tie-breaking: prefer GPU with lower current KVPR or more free space
                        if gpu_kvprs[gpu_id] < gpu_kvprs[best_gpu] or \
                           (gpu_kvprs[gpu_id] == gpu_kvprs[best_gpu] and \
                            GPU_MEM_SIZE - gpu_current_sizes[gpu_id] > GPU_MEM_SIZE - gpu_current_sizes[best_gpu]):
                            best_gpu = gpu_id

            if best_gpu != -1:
                placement[best_gpu].append(model)
                gpu_current_sizes[best_gpu] += model.model_size
                gpu_kvprs[best_gpu] = calculate_gpu_kvpr(placement[best_gpu], gpu_current_sizes[best_gpu])
            else:
                # This case should ideally not happen if total model size <= gpu_num * 80
                # but as a fallback, assign to a random GPU if possible or if no GPU fits.
                # For this problem, we assume a solution is always possible.
                # If a model cannot fit anywhere, it indicates an issue with input or problem constraints.
                pass # Handle error or return an invalid placement if needed

        return placement

    def simulated_annealing(initial_placement):
        current_placement = {gpu_id: list(models_list) for gpu_id, models_list in initial_placement.items()}
        current_max_kvpr = calculate_max_kvpr(current_placement)

        best_placement = {gpu_id: list(models_list) for gpu_id, models_list in current_placement.items()}
        best_max_kvpr = current_max_kvpr

        temperature = 100.0
        cooling_rate = 0.995
        num_models = len(models)

        for _ in range(MAX_ITERATIONS):
            if temperature < 1e-3:
                break

            # Pick a random model to move
            model_to_move = random.choice(models)
            current_gpu_id = -1
            for gpu_id, gpu_models in current_placement.items():
                if model_to_move in gpu_models:
                    current_gpu_id = gpu_id
                    break

            if current_gpu_id == -1: # Model not found (should not happen if initial_placement is correct)
                continue

            # Try moving the model to another GPU
            possible_target_gpus = list(range(gpu_num))
            if len(possible_target_gpus) > 1:
                possible_target_gpus.remove(current_gpu_id)
                target_gpu_id = random.choice(possible_target_gpus)

                # Create a new placement by moving the model
                new_placement = {gpu_id: list(models_list) for gpu_id, models_list in current_placement.items()}
                new_placement[current_gpu_id].remove(model_to_move)
                new_placement[target_gpu_id].append(model_to_move)

                # Check if the new placement is valid (no GPU overloaded)
                is_valid_move = True
                for gpu_id in range(gpu_num):
                    current_size = sum(m.model_size for m in new_placement[gpu_id])
                    if current_size > GPU_MEM_SIZE:
                        is_valid_move = False
                        break

                if is_valid_move:
                    new_max_kvpr = calculate_max_kvpr(new_placement)

                    # Acceptance probability
                    delta = new_max_kvpr - current_max_kvpr
                    if delta < 0 or random.random() < math.exp(-delta / temperature):
                        current_placement = new_placement
                        current_max_kvpr = new_max_kvpr

                        if current_max_kvpr < best_max_kvpr:
                            best_placement = {gpu_id: list(models_list) for gpu_id, models_list in current_placement.items()}
                            best_max_kvpr = current_max_kvpr

            temperature *= cooling_rate

        return best_placement, best_max_kvpr

