        sa_placement, sa_max_kvpr = simulated_annealing(initial_placement)

        if sa_max_kvpr < overall_min_max_kvpr:
            overall_min_max_kvpr = sa_max_kvpr
            overall_best_placement = sa_placement

    # If SA failed to find anything better than initial greedy, return the best greedy seen
    if overall_best_placement is None:
        return greedy_initial_placement()

    return overall_best_placement
